var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"INTERN_MAIN_NPC_QM","text":{"KOREA":"우웅… 너무 시끄러워…….","JPN":"うーん……うるさーい……","ENG":"Mmmgh... so noisy...","TWN":"呃嗯……太吵了……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_MAIN_NPC_QM","text":{"KOREA":"무슨 소리지…? 아직 컴컴해… 더 자고 싶은데…….","JPN":"何の音……？　まだ暗いよ……もっと寝てたいのに……","ENG":"What's that sound...? It's still dark... I want to sleep a little longer...","TWN":"什麼聲音……？天還很黑呢……我還想再睡一會兒……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"쓰읍……!!","JPN":"じゅる……！！","ENG":"*Slurp…!!*","TWN":"嘶……！！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"헙!? 침 잔뜩 흘려버렸다!","JPN":"ハッ！？　大量のよだれが！","ENG":"Huh?! I drooled all over myself!","TWN":"哇？！流了好多口水！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아, 아무도 못 봤겠지?","JPN":"だ、誰にも見られてないよね？","ENG":"Ah, no one saw that, right?","TWN":"啊，應該沒人看見吧？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"우웅, 이런 멍청한 얼굴… 미나 선배가 봤다간, 못난이 후배라고 생각할 거야…….","JPN":"うーん、こんなだらしない顔……ミナ先輩に見られたらブサイクな後輩だって思われちゃう……","ENG":"Ugh, I looked like such a mess... if Mina saw me like that, she'd totally think I'm hopeless...","TWN":"嗚嗚，這麼蠢的表情……要是被米娜前輩看到了，會覺得我是個笨蛋的……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"어, 어라? 그런데 여긴 어디지? 무슨 영화관 같은데……?","JPN":"あ、あれ？　ここどこ？　なんか映画館っぽいけど……？","ENG":"H-Huh? Wait, where am I? This looks like a movie theater...?","TWN":"呃、咦？這裡是哪裡？好像是電影院……？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아하, 그렇구나! 어쩌면 영화를 보다가 깜빡 잠들어 버렸을지도……!?","JPN":"あっ、そうか！　もしかしたら映画見てる途中で寝落ちしちゃったのかも……！？","ENG":"Aha, that's it! Maybe I dozed off while watching a movie...?!","TWN":"啊哈，是這樣啊！說不定是看電影的時候不小心睡著了吧……？！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"무슨 영화였더라? 뭔가 엄청나게 거대한 우주선이 등장하는 SF 영화였던 것 같은데……?","JPN":"どういう映画だっけ？　なんかもの凄く大きな宇宙船が出てくる、SF映画だった気がするんだけど……？","ENG":"What kind of movie was it again? I vaguely remember some massive spaceship... must've been sci-fi?","TWN":"是什麼電影來著？好像是出現了非常巨大的太空船的科幻電影……？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"하아암~ 재미없는 영화였나 봐. 내용이 하나도 기억 안 나는 걸~","JPN":"ふあ～、きっとつまんない映画だったんだ。内容が全然思い出せないもん～","ENG":"Yaaawn! Must've been boring. I don't remember a single thing about it!","TWN":"哈欠～看來是部無聊的電影，我一點內容都記不住～"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"이상해. 왜 아무도 없지?","JPN":"おかしいな。どうして誰もいないの？","ENG":"This is strange. Where is everyone?","TWN":"奇怪，為什麼沒人？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"영화도 끝났는데 손님을 방치해 두다니… 무슨 극장이 이렇담?","JPN":"映画も終わったのに、客を放置するなんて……変な劇場！","ENG":"The movie's over, but they just left a guest sitting here? What kind of theater does that?","TWN":"電影都結束了還把客人晾在一邊……這是什麼電影院啊？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그래, 출구! 우선 출구부터 찾는 거야!","JPN":"そうだ、出口！　まずは出口を探そう！","ENG":"Okay, the exit! First thing's first. I'll find the exit!","TWN":"對，出口！首先要找到出口！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"허억, 허억……!","JPN":"はあ……はあ……！","ENG":"*Huff* *Huff…!*","TWN":"呵、呵……！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"어두컴컴해서 잘 몰랐는데… 이 극장 엄청 넓잖아? 뛰어도, 뛰어도 끝이 없어!","JPN":"暗くてわからなかったけど、この劇場めちゃくちゃ広くない？　走っても走っても終わりが見えない！","ENG":"It was hard to tell in the dark, but... this theater is huge! I keep running and running, but there's no end in sight!","TWN":"因為太黑了所以沒注意到……這個劇場好大啊！怎麼跑都跑不到盡頭！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아니, 잠깐… 어쩐지 같은 곳을 뺑뺑 돌고 있다는 느낌이…….","JPN":"うん？　ちょっと待って、なんか同じところをぐるぐる回ってるような……","ENG":"Wait... hold on. It feels like I've been running in circles...","TWN":"不，等等……總覺得好像在同一個地方兜圈子……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"대체 여긴 어디지……?","JPN":"ここっていったいどこなの……？","ENG":"Just where am I...?","TWN":"這裡到底是哪裡……？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"저기요! 거기 누구 없나요? 여기 사람 있어요!","JPN":"すみません！　誰かいませんか？　まだ人がいるんですけど！","ENG":"Hello! Is anyone out there? There's someone here!","TWN":"喂！有沒有人啊？這裡有人！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"미나 선배! 어디 있어요! 펠리세트, 라이카! 저 여기에 있다고요!","JPN":"ミナ先輩！　どこですか？　フェリセット、ライカ！　私ここです！","ENG":"Mina! Where are you? Félicette, Laika! I'm right here!","TWN":"米娜前輩！你在哪裡！費莉塞特，萊卡！我在這裡啊！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"다들… 다들 있으면, 대답 좀 해봐요!","JPN":"みんな！　いたら返事をしてください！","ENG":"Everyone... if you're out there, please say something!","TWN":"大家……大家在的話，請回答我一下！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"소용없어요, 노엘 라이트.","JPN":"無駄ですよ、ノエル・ライト。","ENG":"It's pointless, Noelle Wright.","TWN":"沒用的，洛艾兒·萊特。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그들은 이곳에 초대받은 관객이 아니니까요.","JPN":"彼女たちは招かれた観客ではありませんから。","ENG":"They are not guests invited to this place.","TWN":"他們並不是被邀請的觀眾。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};